// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

interface ISingletonFactory {
    function deploy(
        bytes memory initCode,
        bytes32 salt
    ) external returns (address);
}

library ImmutableStorage {
    address public constant SINGLETON_FACTORY =
        0xce0042B868300000d44A59004Da54A005ffdcf9f;

    function store(bytes memory buffer) internal returns (address pointer) {
        bytes memory bytecode = _creationBytecode(buffer);
        pointer = _calculateAddress(bytecode);

        uint256 size;
        assembly {
            size := extcodesize(pointer)
        }

        if (size == 0) {
            assert(
                pointer ==
                    ISingletonFactory(SINGLETON_FACTORY).deploy(
                        bytecode,
                        bytes32(0)
                    )
            );
        }
    }

    /**
     * @notice Reads the runtime bytecode stored at a `pointer` contract, skipping the first byte.
     *
     * @param pointer The address of the deployed pointer contract.
     * @return buffer The raw bytecode (minus the prepended 0x00) read from `pointer`.
     */
    function load(address pointer) internal view returns (bytes memory buffer) {
        assembly {
            let size := sub(extcodesize(pointer), 1)
            // free memory point ought to be multiple of 32
            let rounded := and(add(size, 31), not(31))

            // Get free pointer
            buffer := mload(0x40)
            // Store length
            mstore(buffer, size)
            // Update free pointer
            mstore(0x40, add(add(buffer, 0x20), rounded))

            // Copy code starting from offset 0x01 (skip the 0x00 prefix)
            extcodecopy(pointer, add(buffer, 0x20), 0x01, size)
        }
    }

    /**
     * @notice Generates creation bytecode that deploys a contract containing `data` as its runtime bytecode.
     * @dev The generated constructor copies `data` into memory and returns it as the contract's code.
     *      A leading `0x00` byte is prepended so the resulting contract cannot be called.
     *
     * Assembly layout (constructor):
     *
     * ```
     * 0x00    63 <XXXXXX>   PUSH4 code_size         ; push code length (runtime size)
     * 0x01    80             DUP1                   ; duplicate size
     * 0x02    60 0e          PUSH1 0x0e             ; offset of actual code
     * 0x03    60 00          PUSH1 0x00             ; destination offset
     * 0x04    39             CODECOPY               ; copy <code_size> bytes from offset 0x0e
     * 0x05    60 00          PUSH1 0x00             ; return offset
     * 0x06    f3             RETURN                 ; return code as runtime bytecode
     * <CODE>                                        ; runtime code (0x00 + data)
     * ```
     *
     */
    function _creationBytecode(
        bytes memory data
    ) private pure returns (bytes memory) {
        return
            abi.encodePacked(
                hex"63",
                uint32(data.length + 1),
                hex"80_60_0E_60_00_39_60_00_F3",
                // Prepend 0x00 to prevent the deployed contract from being callable
                hex"00",
                data
            );
    }

    function _calculateAddress(
        bytes memory creationBytecode
    ) private pure returns (address) {
        bytes32 hash = keccak256(
            abi.encodePacked(
                bytes1(0xff),
                SINGLETON_FACTORY,
                bytes32(0),
                keccak256(creationBytecode)
            )
        );
        return address(uint160(uint256(hash)));
    }
}

contracts/common/PriceConversion.sol.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "../periphery/interfaces/IPricing.sol";
import "../types/Types.sol";

/**
 * @title PriceConversion
 * @notice Library for applying exchange rate conversion via IPricing adapters.
 *
 * @dev Converts amounts using an external pricing adapter. The adapter returns
 *      a price with 18 decimals precision. Decimal scaling should be handled
 *      by the caller.
 *
 * @author gnosisguild
 */
library PriceConversion {
    uint256 private constant PRICE_DECIMALS = 18;
    uint256 private constant ONE = 10 ** PRICE_DECIMALS;

    /**
     * @notice Applies exchange rate conversion to an amount.
     * @param amount The amount to convert
     * @param adapter Price adapter address
     * @return status Ok or error status from adapter
     * @return result Amount multiplied by price and divided by 10^18
     */
    function convert(
        uint256 amount,
        address adapter
    ) internal view returns (Status, uint256) {
        (Status status, uint256 price) = _getPrice(adapter);
        if (status != Status.Ok) {
            return (status, 0);
        }

        return (Status.Ok, (amount * price) / ONE);
    }

    /**
     * @dev Safely invokes pricing adapter via staticcall.
     *
     *  Price Adapter (IPricing.getPrice) Error Scenarios:
     *  | Scenario              | staticcall Result     | Behavior                      | Status                          |
     *  |-----------------------|-----------------------|-------------------------------|---------------------------------|
     *  | No code at address    | (true, "")            | extcodesize == 0              | PricingAdapterNotAContract      |
     *  | Wrong interface       | (false, "")           | staticcall fails              | PricingAdapterReverted          |
     *  | Function reverts      | (false, <error data>) | staticcall fails              | PricingAdapterReverted          |
     *  | Returns wrong type    | (true, <len != 32>)   | returnData.length != 32       | PricingAdapterInvalidResult     |
     *  | Returns zero price    | (true, <32 bytes>)    | price == 0                    | PricingAdapterZeroPrice         |
     *
     */

    function _getPrice(address adapter) private view returns (Status, uint256) {
        if (adapter == address(0)) {
            return (Status.Ok, ONE);
        }

        uint256 size;
        assembly {
            size := extcodesize(adapter)
        }
        if (size == 0) {
            return (Status.PricingAdapterNotAContract, 0);
        }

        (bool success, bytes memory returnData) = adapter.staticcall(
            abi.encodeCall(IPricing.getPrice, ())
        );

        if (!success) {
            return (Status.PricingAdapterReverted, 0);
        }

        if (returnData.length != 32) {
            return (Status.PricingAdapterInvalidResult, 0);
        }

        uint256 price = uint256(bytes32(returnData));
        if (price == 0) {
            return (Status.PricingAdapterZeroPrice, 0);
        }

        return (Status.Ok, price);
    }
}

contracts/core/Authorization.sol.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "./evaluate/ConditionEvaluator.sol";
import "./serialize/ConditionLoader.sol";
import "./Storage.sol";

import "../periphery/interfaces/ITransactionUnwrapper.sol";

/**
 * @title   Authorization
 *
 * @notice Authorizes transactions by evaluating role permissions and condition
 *         trees.
 *
 * @dev    The authorization follows three steps:
 *         1. Scope Resolution: Resolves the permission configuration
 *         2. Mode Validation: Checks for value transfer and tx operation
 *         3. Payload Validation: Evaluates condition trees against tx data
 *
 *         Transaction bundles are supported via adapter-based unwrapping.
 *
 * @author  gnosisguild
 */
abstract contract Authorization is RolesStorage {
    function _authorize(
        bytes32 roleKey,
        address to,
        uint256 value,
        bytes calldata data,
        Operation operation
    ) internal view returns (Consumption[] memory consumptions) {
        address adapter = unwrappers[_key(to, bytes4(data))];
        if (adapter == address(0)) {
            return
                _transaction(
                    roleKey,
                    data,
                    consumptions,
                    Transaction(to, value, operation)
                );
        }

        /*
         * Transaction Bundle
         */
        try
            ITransactionUnwrapper(adapter).unwrap(to, value, data, operation)
        returns (UnwrappedTransaction[] memory unwrapped) {
            for (uint256 i; i < unwrapped.length; ++i) {
                UnwrappedTransaction memory entry = unwrapped[i];
                consumptions = _transaction(
                    roleKey,
                    data[entry.dataLocation:entry.dataLocation +
                        entry.dataSize],
                    consumptions,
                    Transaction(entry.to, entry.value, entry.operation)
                );
            }
        } catch {
            revert MalformedMultiEntrypoint();
        }
    }

    /// @dev Inspects a transaction and authorizes based on role permissions.
    function _transaction(
        bytes32 roleKey,
        bytes calldata data,
        Consumption[] memory consumptions,
        Transaction memory transaction
    ) private view returns (Consumption[] memory) {
        Role storage role = roles[roleKey];

        if (data.length != 0 && data.length < 4) {
            revert FunctionSignatureTooShort();
        }

        Clearance clearance = role.clearance[transaction.to];

        /*
         * Resolve scopeConfig:
         * 1- look up target-specific entry
         * 2- fallback on global entry
         */

        // Target entry
        uint256 scopeConfig;
        if (clearance != Clearance.None) {
            bytes32 key = bytes32(bytes20(transaction.to)) |
                /*
                 * Clearance.Target:   set lower 12 bytes to 0xFF..FF
                 * Clearance.Function: set lower 12 bytes to selector
                 */
                (
                    clearance == Clearance.Target
                        ? (~bytes32(0) >> 160)
                        : (bytes32(bytes4(data)) >> 160)
                );

            scopeConfig = role.scopeConfig[key];
        }

        // Global entry
        if (scopeConfig == 0 && data.length != 0) {
            scopeConfig = role.scopeConfig[bytes32(bytes4(data)) >> 160];
        }

        if (scopeConfig == 0) {
            revert TransactionNotAllowed(transaction.to, bytes4(data));
        }

        /*
         * Check ExecutionOptions
         */
        {
            uint256 options = scopeConfig >> 160;
            if (options & 1 == 0 && transaction.value > 0) {
                revert SendNotAllowed(transaction.to);
            }
            if (
                options & 2 == 0 &&
                transaction.operation == Operation.DelegateCall
            ) {
                revert DelegateCallNotAllowed(transaction.to);
            }
        }

        /*
         * Load and Evaluate Condition
         */
        (Condition memory condition, uint256 maxPluckCount) = ConditionLoader
            .load(scopeConfig);

        Result memory result = ConditionEvaluator.evaluate(
            data,
            0,
            condition,
            consumptions,
            Context(
                transaction.to,
                transaction.value,
                transaction.operation,
                new bytes32[](maxPluckCount),
                new uint256[](maxPluckCount)
            )
        );

        if (result.status != Status.Ok) {
            revert ConditionViolation(
                result.status,
                result.violatedNodeIndex,
                result.payloadLocation
            );
        }

        return result.consumptions;
    }
}

contracts/core/evaluate/BitmaskChecker.s.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import {Status} from "../../types/Types.sol";

/**
 * @title BitmaskChecker
 * @notice Validates that a value matches an expected pattern after applying a bitmask.
 *
 * @dev compValue packs shift, mask and expected.
 *
 * @author gnosisguild
 *
 */
library BitmaskChecker {
    function check(
        bytes calldata data,
        uint256 location,
        bytes memory compValue,
        bool inlined
    ) internal pure returns (Status) {
        uint256 shift = uint16(bytes2(compValue));
        uint256 length = (compValue.length - 2) / 2;

        uint256 start = location + (inlined ? 0 : 32);
        uint256 end = data.length;

        if (shift + length > end - start) {
            return Status.BitmaskOverflow;
        }

        bytes calldata value = data[start:];

        /*
         * Load actual, expected, and mask in 32-byte chunks. Final chunk
         * gets rinsed if less than 32 bytes remain.
         */
        for (uint256 i; i < length; i += 32) {
            /*
             * compValue memory layout:
             * | 32: length | 2: shift | N: mask | N: expected |
             *                         ^--- 0x22 offset
             */
            bytes32 mask;
            assembly {
                mask := mload(add(add(compValue, 0x22), i))
            }

            bytes32 expected;
            assembly {
                expected := mload(add(add(compValue, 0x22), add(length, i)))
            }

            bytes32 actual;
            assembly {
                actual := calldataload(add(value.offset, add(shift, i)))
            }

            bytes32 rinseMask = _rinseMask(length - i);

            if (expected & rinseMask != actual & mask & rinseMask) {
                return Status.BitmaskNotAllowed;
            }
        }

        return Status.Ok;
    }

    /// @dev Returns a mask with leading 1s for byteCount bytes, rest 0s.
    function _rinseMask(uint256 bytesLeft) private pure returns (bytes32) {
        uint256 bitsToRinse = (bytesLeft > 31 ? 0 : 32 - bytesLeft) * 8;
        return bytes32(type(uint256).max << bitsToRinse);
    }
}

contracts/core/evaluate/ConditionEvaluat.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "./BitmaskChecker.sol";
import "./CustomConditionChecker.sol";
import "./WithinAllowanceChecker.sol";
import "./WithinRatioChecker.sol";

import "../../common/AbiLocation.sol";

import "../../types/Types.sol";

/**
 * @title ConditionEvaluator
 * @notice Evaluates condition trees on scoped function calls.
 * @author gnosisguild
 */
library ConditionEvaluator {
    function evaluate(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) internal view returns (Result memory) {
        Operator operator = condition.operator;

        if (operator < Operator.EqualTo) {
            if (operator == Operator.Pass) {
                return _ok(consumptions);
            } else if (operator == Operator.Matches) {
                location = location > 0 &&
                    condition.encoding == Encoding.AbiEncoded
                    ? location + 32
                    : location;
                return
                    _matches(data, location, condition, consumptions, context);
            } else if (operator == Operator.And) {
                return _and(data, location, condition, consumptions, context);
            } else if (operator == Operator.Or) {
                return _or(data, location, condition, consumptions, context);
            } else if (operator == Operator.Slice) {
                return _slice(data, location, condition, consumptions, context);
            } else if (operator == Operator.Pluck) {
                return _pluck(data, location, condition, consumptions, context);
            } else if (operator == Operator.Empty) {
                return
                    _result(
                        data.length == 0 ? Status.Ok : Status.CalldataNotEmpty,
                        0,
                        condition,
                        consumptions
                    );
            } else if (
                operator == Operator.ArraySome ||
                operator == Operator.ArrayEvery
            ) {
                return
                    _arrayIterator(
                        data,
                        location,
                        condition,
                        consumptions,
                        context
                    );
            } else if (operator == Operator.ArrayTailMatches) {
                return
                    _arrayTailMatches(
                        data,
                        location,
                        condition,
                        consumptions,
                        context
                    );
            } else {
                // ZipSome or ZipEvery
                return
                    _zipIterator(
                        data,
                        location,
                        condition,
                        consumptions,
                        context
                    );
            }
        } else {
            if (operator <= Operator.SignedIntLessThan) {
                (bytes32 value, bool overflow) = __input(
                    data,
                    location,
                    condition,
                    context
                );

                return
                    _result(
                        overflow
                            ? Status.CalldataOverflow
                            : operator <= Operator.LessThan
                                ? __compare(value, condition)
                                : __compareSigned(value, condition),
                        location,
                        condition,
                        consumptions
                    );
            } else if (operator == Operator.Bitmask) {
                return
                    _result(
                        BitmaskChecker.check(
                            data,
                            location,
                            condition.compValue,
                            condition.inlined
                        ),
                        location,
                        condition,
                        consumptions
                    );
            } else if (operator == Operator.WithinAllowance) {
                (bytes32 value, bool overflow) = __input(
                    data,
                    location,
                    condition,
                    context
                );
                if (overflow) {
                    return
                        _violation(
                            Status.CalldataOverflow,
                            location,
                            condition
                        );
                }
                return
                    __allowance(
                        uint256(value),
                        location,
                        condition,
                        consumptions
                    );
            } else if (operator == Operator.CallWithinAllowance) {
                return __allowance(1, location, condition, consumptions);
            } else if (operator == Operator.WithinRatio) {
                return
                    _result(
                        WithinRatioChecker.check(
                            condition.compValue,
                            context.pluckedValues
                        ),
                        location,
                        condition,
                        consumptions
                    );
            } else {
                // Custom
                return
                    _result(
                        CustomConditionChecker.check(
                            condition.compValue,
                            context.to,
                            context.value,
                            data,
                            context.operation,
                            location,
                            condition,
                            context.pluckedValues
                        ),
                        location,
                        condition,
                        consumptions
                    );
            }
        }
    }

    function _matches(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        uint256 shift = 32 - condition.compValue.length;
        if (shift < 32) {
            /*
             * Leading Bytes Validation
             *
             * For AbiEncoded + Matches, compValue might contain N bytes that must
             * match the first N bytes of calldata at location.
             *
             * Integrity.sol validates N <= 32, so shift underflow is impossible.
             *
             * Comparison uses right-alignment in bytes32:
             *   shift = 32 - N
             *   expected: bytes32(compValue)  >> shift  (N bytes, right-aligned)
             *   actual:   bytes32(data[loc:]) >> shift  (N bytes, right-aligned)
             *
             * If compValue is empty (shift == 32), validation is skipped.
             */

            // Check bounds before reading leading bytes
            if (location + (32 - shift) > data.length) {
                return _violation(Status.CalldataOverflow, location, condition);
            }

            bytes32 expected = bytes32(condition.compValue) >> shift;
            bytes32 actual = bytes32(data[location:]) >> shift;

            if (expected != actual) {
                return
                    _violation(
                        Status.LeadingBytesNotAMatch,
                        location,
                        condition
                    );
            }
        }

        // Decode children locations - all children are structural
        (uint256[] memory childLocations, bool overflow) = AbiLocation.children(
            data,
            location + condition.leadingBytes,
            condition
        );

        if (overflow) {
            return _violation(Status.CalldataOverflow, location, condition);
        }

        if (condition.children.length != childLocations.length) {
            return _violation(Status.ParameterNotAMatch, location, condition);
        }

        result.consumptions = consumptions;
        for (uint256 i; i < childLocations.length; ++i) {
            result = evaluate(
                data,
                childLocations[i],
                condition.children[i],
                result.consumptions,
                context
            );
            if (result.status != Status.Ok) {
                return result;
            }
        }
        return result;
    }

    function _and(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        result.consumptions = consumptions;
        for (uint256 i; i < condition.children.length; ++i) {
            result = evaluate(
                data,
                location,
                condition.children[i],
                result.consumptions,
                context
            );
            if (result.status != Status.Ok) {
                return result;
            }
        }
        return result;
    }

    function _or(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        for (uint256 i; i < condition.children.length; ++i) {
            result = evaluate(
                data,
                location,
                condition.children[i],
                consumptions,
                context
            );
            if (result.status == Status.Ok) {
                return result;
            }
        }

        return _violation(Status.OrViolation, location, condition);
    }

    function _arrayIterator(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        bool every = condition.operator == Operator.ArrayEvery;

        (uint256[] memory childLocations, bool overflow) = AbiLocation.children(
            data,
            location,
            condition
        );

        if (overflow) {
            return _violation(Status.CalldataOverflow, location, condition);
        }

        result.consumptions = consumptions;
        for (uint256 i; i < childLocations.length; ++i) {
            result = evaluate(
                data,
                childLocations[i],
                condition.children[0],
                every ? result.consumptions : consumptions,
                context
            );

            if (every) {
                if (result.status != Status.Ok) {
                    result.status = Status.NotEveryArrayElementPasses;
                    return result;
                }
            } else {
                if (result.status == Status.Ok) {
                    return result;
                }
            }
        }

        return
            every
                ? result
                : _violation(Status.NoArrayElementPasses, location, condition);
    }

    function _arrayTailMatches(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        // Decode array element locations
        (uint256[] memory childLocations, bool overflow) = AbiLocation.children(
            data,
            location,
            condition
        );

        if (overflow) {
            return _violation(Status.CalldataOverflow, location, condition);
        }

        uint256 conditionCount = condition.children.length;
        uint256 childCount = childLocations.length;

        if (childCount < conditionCount) {
            return _violation(Status.ParameterNotAMatch, location, condition);
        }

        uint256 tailOffset = childCount - conditionCount;

        result.consumptions = consumptions;
        for (uint256 i; i < conditionCount; ++i) {
            result = evaluate(
                data,
                childLocations[tailOffset + i],
                condition.children[i],
                result.consumptions,
                context
            );

            if (result.status != Status.Ok) {
                return result;
            }
        }
        return result;
    }

    function _zipIterator(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        bool every = condition.operator == Operator.ZipEvery;

        (
            uint256[][] memory locations,
            uint256 length,
            Status status
        ) = _zipLocations(data, condition, context);

        if (status != Status.Ok) {
            return _violation(status, location, condition);
        }

        Condition[] memory fields = condition.children[0].children;

        result.consumptions = consumptions;
        for (uint256 i; i < length; ++i) {
            // For ZipSome, we always start from base consumptions.
            if (!every) result.consumptions = consumptions;

            bool tuplePasses = true;
            for (uint256 f; f < fields.length; ++f) {
                result = evaluate(
                    data,
                    locations[f][i],
                    fields[f],
                    result.consumptions,
                    context
                );
                if (result.status != Status.Ok) {
                    tuplePasses = false;
                    break;
                }
            }

            if (every) {
                if (!tuplePasses) {
                    result.status = Status.NotEveryZippedElementPasses;
                    return result;
                }
            } else {
                if (tuplePasses) {
                    return result;
                }
            }
        }

        return
            every
                ? result
                : _violation(Status.NoZippedElementPasses, location, condition);
    }

    /*
     * Slice computes a new location pointing to a byte-range within the
     * current location, so the child transparently evaluates against that
     * slice.
     *
     * The child will read the slice via __input, which right-aligns values
     * <=32 bytes to match comparison compValue encoding.
     */
    function _slice(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private view returns (Result memory result) {
        // compValue layout: | 2 bytes: shift | 1 byte: size (1-32)
        uint16 shift = uint16(bytes2(condition.compValue));
        uint8 size = uint8(condition.compValue[2]);

        Condition memory sliced = condition.children[0];
        sliced.size = size;

        return
            evaluate(
                data,
                // compute the slices location
                location + (condition.inlined ? 0 : 32) + shift,
                sliced,
                consumptions,
                context
            );
    }

    function _pluck(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions,
        Context memory context
    ) private pure returns (Result memory) {
        (bytes32 pluckedValue, bool overflow) = __input(
            data,
            location,
            condition,
            context
        );
        if (overflow) {
            return _violation(Status.CalldataOverflow, location, condition);
        }

        uint256 index = uint8(condition.compValue[0]);
        context.pluckedLocations[index] = location;
        context.pluckedValues[index] = pluckedValue;

        return _ok(consumptions);
    }

    function __compare(
        bytes32 value,
        Condition memory condition
    ) private pure returns (Status) {
        bytes32 compValue = condition.compValue.length > 32
            ? keccak256(condition.compValue)
            : bytes32(condition.compValue);

        if (condition.operator == Operator.EqualTo) {
            return value == compValue ? Status.Ok : Status.ParameterNotAllowed;
        }
        if (condition.operator == Operator.GreaterThan) {
            return
                value > compValue ? Status.Ok : Status.ParameterLessThanAllowed;
        }
        return
            value < compValue ? Status.Ok : Status.ParameterGreaterThanAllowed;
    }

    function __compareSigned(
        bytes32 rawValue,
        Condition memory condition
    ) private pure returns (Status) {
        int256 value = int256(uint256(rawValue));
        int256 compValue = int256(uint256(bytes32(condition.compValue)));

        if (condition.operator == Operator.SignedIntGreaterThan) {
            return
                value > compValue ? Status.Ok : Status.ParameterLessThanAllowed;
        }
        return
            value < compValue ? Status.Ok : Status.ParameterGreaterThanAllowed;
    }

    function __allowance(
        uint256 value,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions
    ) private view returns (Result memory) {
        (
            Status status,
            Consumption[] memory nextConsumptions
        ) = WithinAllowanceChecker.check(
                consumptions,
                value,
                condition.compValue
            );

        return _result(status, location, condition, nextConsumptions);
    }

    /**
     * @dev Reads a value from calldata or from Transaction.value, right-aligning when needed.
     *      - Encoding.None: returns context.value (ether amount)
     *      - size <= 32: reads from calldata and right-aligns
     *      - size > 32: returns keccak256 hash of the calldata slice
     *
     * @param data      The calldata to read from.
     * @param location  The location in calldata.
     * @param condition The condition with layout info.
     * @param context   The execution context (for ether value).
     * @return result   The value as bytes32, right-aligned or hashed.
     */
    function __input(
        bytes calldata data,
        uint256 location,
        Condition memory condition,
        Context memory context
    ) private pure returns (bytes32 result, bool overflow) {
        /*
         * Integrity rules map Encoding.EtherValue -> Encoding.None during packing.
         * If we encounter Encoding.None here (in a comparison context), it acts as
         * a virtual static parameter representing the transaction value.
         */
        if (condition.encoding == Encoding.None) {
            return (bytes32(context.value), false);
        }

        // Check if condition has size set (e.g., from Slice), otherwise get from decoder
        uint256 size = condition.size != 0
            ? condition.size
            : AbiLocation.size(data, location, condition);

        if (location + size > data.length) {
            return (0, true);
        }

        if (size == 32) {
            assembly {
                result := calldataload(add(data.offset, location))
            }
            return (result, false);
        }

        // align the word for slicing
        if (size < 32) {
            return (
                bytes32(data[location:location + size]) >> ((32 - size) * 8),
                false
            );
        }

        // size > 32
        return (keccak256(data[location:location + size]), false);
    }

    function _ok(
        Consumption[] memory consumptions
    ) private pure returns (Result memory) {
        return
            Result({
                status: Status.Ok,
                violatedNodeIndex: 0,
                payloadLocation: 0,
                consumptions: consumptions
            });
    }

    function _violation(
        Status status,
        uint256 location,
        Condition memory condition
    ) private pure returns (Result memory) {
        Consumption[] memory empty;
        return
            Result({
                status: status,
                violatedNodeIndex: condition.index,
                payloadLocation: location,
                consumptions: empty
            });
    }

    function _result(
        Status status,
        uint256 location,
        Condition memory condition,
        Consumption[] memory consumptions
    ) private pure returns (Result memory) {
        return
            status == Status.Ok
                ? _ok(consumptions)
                : _violation(status, location, condition);
    }

    /**
     * @dev Resolves element locations for arrays being zipped together.
     *
     * @param data      The calldata being evaluated.
     * @param condition The Zip condition (ZipSome / ZipEvery).
     * @param context   Evaluation context with pluckedLocations.
     *
     * @return result One uint256[] per array – element locations in calldata.
     * @return length The common length of all zipped arrays.
     * @return status Status.Ok, or an error
     */
    function _zipLocations(
        bytes calldata data,
        Condition memory condition,
        Context memory context
    )
        private
        pure
        returns (uint256[][] memory result, uint256 length, Status status)
    {
        Condition[] memory fields = condition.children[0].children;
        Condition memory stub;
        stub.encoding = Encoding.Array;
        stub.children = new Condition[](1);

        result = new uint256[][](fields.length);

        for (uint256 f; f < fields.length; ++f) {
            stub.children[0] = fields[f];
            (uint256[] memory locations, bool overflow) = AbiLocation.children(
                data,
                context.pluckedLocations[uint8(condition.compValue[f])],
                stub
            );

            if (overflow) return (result, 0, Status.CalldataOverflow);

            if (f == 0) {
                length = locations.length;
            } else {
                if (length != locations.length) {
                    return (result, 0, Status.ZippedArrayLengthMismatch);
                }
            }

            result[f] = locations;
        }
    }
}

contracts/core/evaluate/CustomConditionC.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "../../periphery/interfaces/ICustomCondition.sol";
import "../../types/Types.sol";
import "../../common/AbiLocation.sol";

/**
 * @title CustomConditionChecker
 * @notice Validates transactions against external custom condition adapters.
 *
 * @dev Safely invokes ICustomCondition.check via staticcall, handling all
 *      error scenarios:
 *
 *   | Scenario              | staticcall Result     | Behavior                      | Status                          |
 *   |-----------------------|-----------------------|-------------------------------|---------------------------------|
 *   | No code at address    | (true, "")            | extcodesize == 0              | CustomConditionNotAContract     |
 *   | Wrong interface       | (false, "")           | staticcall fails              | CustomConditionReverted         |
 *   | Function reverts      | (false, <error data>) | staticcall fails              | CustomConditionReverted         |
 *   | Returns wrong type    | (true, <len != 32>)   | returnData.length != 32       | CustomConditionInvalidResult    |
 *   | Returns false         | (true, <32 bytes>)    | Adapter rejects the condition | CustomConditionViolation        |
 *
 * @author gnosisguild
 */
library CustomConditionChecker {
    /**
     * @notice Evaluates a custom condition against an external adapter.
     * @param compValue Packed config: adapter address (20 bytes) + optional extra data
     * @param to Target address of the transaction
     * @param value ETH value of the transaction
     * @param data Calldata of the transaction
     * @param operation Call or DelegateCall
     * @param location Byte offset into calldata
     * @param condition The condition with payload info for size computation
     * @param pluckedValues Array of previously plucked values
     * @return status Ok if condition passes, error status otherwise
     */
    function check(
        bytes memory compValue,
        address to,
        uint256 value,
        bytes calldata data,
        Operation operation,
        uint256 location,
        Condition memory condition,
        bytes32[] memory pluckedValues
    ) internal view returns (Status status) {
        address adapter = address(bytes20(compValue));

        uint256 size = condition.size != 0
            ? condition.size
            : AbiLocation.size(data, location, condition);

        bytes memory extra;
        if (compValue.length > 20) {
            assembly {
                let len := sub(mload(compValue), 20)
                extra := mload(0x40)
                mstore(0x40, add(extra, add(0x40, len)))
                mstore(extra, len)
                mcopy(add(extra, 0x20), add(compValue, 0x34), len)
            }
        }

        return
            _invoke(
                adapter,
                to,
                value,
                data,
                operation,
                location,
                size,
                extra,
                pluckedValues
            );
    }

    /**
     * @dev Safely invokes the adapter via staticcall.
     */
    function _invoke(
        address adapter,
        address to,
        uint256 value,
        bytes calldata data,
        Operation operation,
        uint256 location,
        uint256 size,
        bytes memory extra,
        bytes32[] memory pluckedValues
    ) private view returns (Status) {
        uint256 codeSize;
        assembly {
            codeSize := extcodesize(adapter)
        }
        if (codeSize == 0) {
            return Status.CustomConditionNotAContract;
        }

        (bool callSuccess, bytes memory returnData) = adapter.staticcall(
            abi.encodeCall(
                ICustomCondition.check,
                (
                    to,
                    value,
                    data,
                    operation,
                    location,
                    size,
                    extra,
                    pluckedValues
                )
            )
        );

        if (!callSuccess) {
            return Status.CustomConditionReverted;
        }

        if (returnData.length != 32) {
            return Status.CustomConditionInvalidResult;
        }

        bool success = abi.decode(returnData, (bool));
        if (!success) {
            return Status.CustomConditionViolation;
        }

        return Status.Ok;
    }
}

contracts/core/evaluate/WithinAllowanceC.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "../../common/AllowanceLoader.sol";
import "../../common/ConsumptionList.sol";
import "../../common/PriceConversion.sol";
import "../../types/Types.sol";

import {Consumption} from "../../types/Allowance.sol";

/**
 * @title WithinAllowanceChecker
 * @notice Validates allowance consumption with optional amount conversion.
 *
 * @dev Checks if a value is within an allowance and consumes it. The value is
 *      normalized to the allowance's base denomination via decimal scaling
 *      and/or exchange rate conversion.
 *
 *      The `consumptions` array is treated as immutable. If consumption occurs,
 *      a new array is allocated and returned (Copy-on-Write).
 *
 * @author gnosisguild
 */
library WithinAllowanceChecker {
    function check(
        Consumption[] memory consumptions,
        uint256 value,
        bytes memory compValue
    ) internal view returns (Status status, Consumption[] memory) {
        bytes32 allowanceKey = bytes32(compValue);

        // 1. Convert value to base denomination
        (status, value) = _convert(value, compValue);
        if (status != Status.Ok) {
            return (status, consumptions);
        }

        // 2. Find in list
        uint256 index;
        for (; index < consumptions.length; ++index) {
            if (consumptions[index].allowanceKey == allowanceKey) break;
        }

        // 3. Copy existing or load from storage
        Consumption memory consumption;
        if (index < consumptions.length) {
            consumption = Consumption(
                allowanceKey,
                consumptions[index].balance,
                consumptions[index].consumed,
                consumptions[index].timestamp
            );
        } else {
            (uint128 balance, uint64 timestamp) = AllowanceLoader.accrue(
                allowanceKey,
                uint64(block.timestamp)
            );
            consumption = Consumption(allowanceKey, balance, 0, timestamp);
        }

        // 4. Check overflow before consuming
        if (consumption.consumed + value > type(uint128).max) {
            return (Status.AllowanceValueOverflow, consumptions);
        }

        // 5. Consume
        consumption.consumed += uint128(value);

        // 6. Check balance
        if (consumption.consumed > consumption.balance) {
            return (Status.AllowanceExceeded, consumptions);
        }

        // 7. Return updated list
        return (
            Status.Ok,
            ConsumptionList.copyOnWrite(consumptions, consumption, index)
        );
    }

    /**
     * @dev Normalizes a value to the allowance's base denomination.
     *
     *      Calculates the final amount via decimal scaling and optionally
     *      an exchange rate (via price adapter). Scaling is possible without
     *      an adapter by providing both base and param decimals.
     *
     * @param value The raw amount to be converted.
     * @param compValue Configuration bytes containing decimals and adapter.
     * @return status Result of the conversion (Ok or price adapter error).
     * @return converted Normalized amount in the allowance's base decimals.
     */
    function _convert(
        uint256 value,
        bytes memory compValue
    ) private view returns (Status, uint256) {
        /**
         * CompValue Layout (32, 34, or 54 bytes):
         * ┌─────────────────────────┬──────────┬──────────┬─────────────────────┐
         * │      allowanceKey       │   base   │  param   │       adapter       │
         * │        (bytes32)        │ decimals │ decimals │      (address)      │
         * ├─────────────────────────┼──────────┼──────────┼─────────────────────┤
         * │         0 - 31          │    32    │    33    │       34 - 53       │
         * └─────────────────────────┴──────────┴──────────┴─────────────────────┘
         *                           └── optional ─────────┴───── optional ──────┘
         *
         * baseDecimals: decimals of the allowance unit  (how it's accounted)
         * paramDecimals: decimals of the parameter value (from calldata)
         */

        if (compValue.length == 32) {
            return (Status.Ok, value);
        }

        uint256 baseDecimals = uint8(compValue[32]);
        uint256 paramDecimals = uint8(compValue[33]);

        // Scale decimals
        if (baseDecimals >= paramDecimals) {
            value = value * (10 ** (baseDecimals - paramDecimals));
        } else {
            value = value / (10 ** (paramDecimals - baseDecimals));
        }

        address adapter;
        if (compValue.length > 34) {
            assembly {
                adapter := shr(96, mload(add(compValue, 0x42)))
            }
        }

        return PriceConversion.convert(value, adapter);
    }
}

contracts/core/evaluate/WithinRatioCheck.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "../../common/PriceConversion.sol";
import "../../types/Types.sol";

/**
 * @title WithinRatioChecker
 * @notice Validates that a relative amount falls within a ratio range of a
 *         reference amount, with optional price adapter conversion.
 *
 * @dev Ratio is computed in basis points (10000 = 100%). Both amounts are read
 *      from pluckedValues by index, scaled to shared precision, optionally
 *      converted via price adapters, then compared against [minRatio, maxRatio].
 *
 * @author gnosisguild
 */
library WithinRatioChecker {
    /**
     * @dev Configuration decoded from compValue bytes.
     *
     *
     * Layout (12 or 52 bytes):
     * ┌───────────────────┬───────────────────┬───────────────────┬───────────────────┬────────────┬────────────┬───────────────────┬───────────────────┐
     * │ referencePluckIdx │ referenceDecimals │ relativePluckIdx  │ relativeDecimals  │  minRatio  │  maxRatio  │ referenceAdapter  │ relativeAdapter   │
     * │      (uint8)      │      (uint8)      │      (uint8)      │      (uint8)      │  (uint32)  │  (uint32)  │     (address)     │     (address)     │
     * ├───────────────────┼───────────────────┼───────────────────┼───────────────────┼────────────┼────────────┼───────────────────┼───────────────────┤
     * │         0         │         1         │         2         │         3         │    4–7     │    8–11    │      12–31        │      32–51        │
     * └───────────────────┴───────────────────┴───────────────────┴───────────────────┴────────────┴────────────┴───────────────────┴───────────────────┘
     *                                                                                                          └─────────────────── optional ──────────┘
     */
    struct CompValue {
        uint8 referencePluckIndex;
        uint8 referenceDecimals;
        uint8 relativePluckIndex;
        uint8 relativeDecimals;
        uint32 minRatio;
        uint32 maxRatio;
        address referenceAdapter;
        address relativeAdapter;
    }

    uint256 private constant BPS = 10000;

    /**
     * @notice Checks if ratio of relative to reference amount is within bounds.
     * @param compValue Packed configuration bytes
     * @param pluckedValues Array of values extracted from calldata
     * @return Status Ok if within bounds, error status otherwise
     */
    function check(
        bytes memory compValue,
        bytes32[] memory pluckedValues
    ) internal view returns (Status) {
        CompValue memory config = _unpack(compValue);
        (
            Status status,
            uint256 referenceAmount,
            uint256 relativeAmount
        ) = _convert(config, pluckedValues);
        if (status != Status.Ok) {
            return status;
        }

        /*
         *                 relativeAmount × priceRel
         *   ratio (bps) = ───────────────────────── × 10,000
         *                 referenceAmount × priceRef
         */
        uint256 ratio = (relativeAmount * BPS) / referenceAmount;

        if (config.minRatio != 0 && ratio < config.minRatio) {
            return Status.RatioBelowMin;
        }
        if (config.maxRatio != 0 && ratio > config.maxRatio) {
            return Status.RatioAboveMax;
        }

        return Status.Ok;
    }

    /**
     * @dev Extracts and converts reference and relative amounts for ratio comparison.
     *
     *      1. Reads raw values from pluckedValues by index
     *      2. Scales both to the higher decimal precision
     *      3. Applies price adapters (if configured)
     */
    function _convert(
        CompValue memory config,
        bytes32[] memory pluckedValues
    )
        private
        view
        returns (Status status, uint256 referenceAmount, uint256 relativeAmount)
    {
        uint256 precision = config.referenceDecimals > config.relativeDecimals
            ? config.referenceDecimals
            : config.relativeDecimals;

        (status, referenceAmount) = _scaleAndPrice(
            uint256(pluckedValues[config.referencePluckIndex]),
            config.referenceDecimals,
            precision,
            config.referenceAdapter
        );
        if (status != Status.Ok) return (status, 0, 0);

        (status, relativeAmount) = _scaleAndPrice(
            uint256(pluckedValues[config.relativePluckIndex]),
            config.relativeDecimals,
            precision,
            config.relativeAdapter
        );
        if (status != Status.Ok) return (status, 0, 0);
    }

    function _scaleAndPrice(
        uint256 value,
        uint256 decimals,
        uint256 precision,
        address adapter
    ) private view returns (Status, uint256) {
        return
            PriceConversion.convert(
                value * (10 ** (precision - decimals)),
                adapter
            );
    }

    function _unpack(
        bytes memory compValue
    ) private pure returns (CompValue memory config) {
        bytes32 packed = bytes32(compValue);

        config.referencePluckIndex = uint8(bytes1(packed));
        config.referenceDecimals = uint8(bytes1(packed << 8));
        config.relativePluckIndex = uint8(bytes1(packed << 16));
        config.relativeDecimals = uint8(bytes1(packed << 24));
        config.minRatio = uint32(bytes4(packed << 32));
        config.maxRatio = uint32(bytes4(packed << 64));
        config.referenceAdapter = address(bytes20(packed << 96));

        if (compValue.length > 32) {
            assembly {
                mstore(add(config, 0xe0), shr(96, mload(add(compValue, 0x40))))
            }
        }
    }
}

contracts/core/Membership.sol.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "./Storage.sol";

/**
 * @title   Membership
 * @notice  Validates that a module holds an active role membership before
 *          authorizing transactions. Memberships can be time-bound and
 *          usage-limited.
 *
 * @dev     moduleOnly reverts if the call is not sent or signed by an enabled
 *          module. Membership packs timestamps and uses into a single uint256.
 *          See layout below.
 *
 * @author  gnosisguild
 */

abstract contract Membership is RolesStorage {
    uint256 private constant _MEMBERSHIP_NOOP = type(uint256).max;
    uint256 private constant _MEMBERSHIP_REVOKE = 0;

    function _authenticate(
        bytes32 roleKey
    ) internal moduleOnly returns (address module, uint256 nextMembership) {
        // Never authorize the zero role
        if (roleKey == 0) {
            revert NoMembership();
        }

        module = sentOrSignedByModule();

        uint256 membership = roles[roleKey].members[module];
        if (membership == 0) {
            revert NoMembership();
        }

        /*
         * Membership Layout (256 bits)
         * ┌────────────────┬────────────────┬─────────────────────────────────┐
         * │ startTimestamp │  endTimestamp  │            usesLeft             │
         * │    64 bits     │    64 bits     │            128 bits             │
         * └────────────────┴────────────────┴─────────────────────────────────┘
         *
         * - startTimestamp: Unix timestamp when membership becomes valid
         * - endTimestamp:   Unix timestamp when membership expires
         * - usesLeft:       Remaining uses (type(uint128).max = unlimited)
         */

        if (block.timestamp < uint64(membership >> 192)) {
            revert MembershipNotYetValid();
        }
        if (block.timestamp > uint64(membership >> 128)) {
            revert MembershipExpired();
        }
        if (~membership << 128 == 0) {
            // unlimited uses
            return (module, _MEMBERSHIP_NOOP);
        }

        uint256 usesLeft = (membership << 128) >> 128;

        return (
            module,
            usesLeft <= 1
                ? _MEMBERSHIP_REVOKE
                : ((membership >> 128) << 128) | (usesLeft - 1)
        );
    }

    function _hasActiveMembership(
        bytes32 roleKey,
        address module
    ) internal view returns (bool) {
        if (roleKey == 0) return false;
        uint256 membership = roles[roleKey].members[module];
        if (membership == 0) return false;
        if (block.timestamp < uint64(membership >> 192)) return false;
        if (block.timestamp > uint64(membership >> 128)) return false;
        return true;
    }
}

contracts/core/serialize/ConditionLoader.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "../../common/ImmutableStorage.sol";

import "./ConditionUnpacker.sol";

import "../../types/Types.sol";

/**
 * @title ConditionLoader
 * @notice Loads and unpacks condition trees from immutable storage.
 *
 * @author gnosisguild
 */
library ConditionLoader {
    /**
     * @param scopeConfig Packed scopeSonfig (options << 160 | pointer).
     * @return condition The unpacked condition tree with embedded layout.
     * @return maxPluckIndex Maximum pluck index for pluck bag allocation.
     */
    function load(
        uint256 scopeConfig
    )
        internal
        view
        returns (Condition memory condition, uint256 maxPluckIndex)
    {
        address pointer = address(uint160(scopeConfig));
        bytes memory buffer = ImmutableStorage.load(pointer);
        return ConditionUnpacker.unpack(buffer);
    }
}

contracts/core/serialize/ConditionPacker.content:
// SPDX-License-Identifier: BUSL-1.1
// Copyright (c) 2026 GG DAO LLC
// Zodiac Roles Modifier v3
// Converts to LGPL-3.0-or-later on 2030-03-01
pragma solidity >=0.8.17 <0.9.0;

import "./Topology.sol";

/**
 * @title  ConditionPacker
 * @notice A library that provides packing functions for conditions,
 *         transforming ConditionsFlat[] into a memory-optimized buffer.
 *
 * @dev    This library is NOT gas-sensitive since packing is intended to be
 *         called as a helper function within a view entrypoint.
 *
 * @author gnosisguild
 *
 * ╔════════════════════════════════ BUFFER ═════════════════════════════════╗
 * ║ ┌─────────────────────────────────────────────────────────────────────┐ ║
 * ║ │ HEADER (3 bytes = 24 bits)                                          │ ║
 * ║ ├─────────────────────────────────────────────────────────────────────┤ ║
 * ║ │ • conditionNodeCount     16 bits (bytes 0-1)                        │ ║
 * ║ │ • maxPluckValue           8 bits (byte 2)                           │ ║
 * ║ └─────────────────────────────────────────────────────────────────────┘ ║
 * ║ ┌─────────────────────────────────────────────────────────────────────┐ ║
 * ║ │ NODES (nodeCount × 4 bytes each)                                    │ ║
 * ║ ├─────────────────────────────────────────────────────────────────────┤ ║
 * ║ │ Each node (32 bits = 4 bytes):                                      │ ║
 * ║ │   • encoding              3 bits  [31-29]                           │ ║
 * ║ │   • operator              5 bits  [28-24]                           │ ║
 * ║ │   • childCount           10 bits  [23-14]                           │ ║
 * ║ │   • inlinedSize          13 bits  [13-1]                            │ ║
 * ║ │   • hasCompValue          1 bit   [0]                               │ ║
 * ║ └─────────────────────────────────────────────────────────────────────┘ ║
 * ║ ┌─────────────────────────────────────────────────────────────────────┐ ║
 * ║ │ COMPVALUES (variable length)                                        │ ║
 * ║ ├─────────────────────────────────────────────────────────────────────┤ ║
 * ║ │ For each node with hasCompValue=true (in BFS order):                │ ║
 * ║ │   • length               16 bits  (compValue byte length)           │ ║
 * ║ │   • data                 N bytes  (actual compValue data)           │ ║
 * ║ └─────────────────────────────────────────────────────────────────────┘ ║
 * ╚═════════════════════════════════════════════════════════════════════════╝
 *
 */
library ConditionPacker {
    uint256 private constant HEADER_BYTES = 3;
    uint256 private constant NODE_BYTES = 4;

    function pack(
        ConditionFlat[] memory conditions
    ) internal pure returns (bytes memory buffer) {
        _transform(conditions);

        (uint256 compValuesSize, uint256 maxPluckCount) = _count(conditions);

        uint256 nodeCount = conditions.length;

        buffer = new bytes(
            HEADER_BYTES + nodeCount * NODE_BYTES + compValuesSize
        );

        uint256 header = (nodeCount << 8) | maxPluckCount;
        assembly {
            mstore(add(buffer, 0x20), shl(232, header))
        }

        _packNodes(conditions, buffer);
    }

    function _packNodes(
        ConditionFlat[] memory conditions,
        bytes memory buffer
    ) private pure {
        uint256 offset = HEADER_BYTES;
        uint256 compValueOffset = HEADER_BYTES + conditions.length * NODE_BYTES;

        for (uint256 i; i < conditions.length; ++i) {
            ConditionFlat memory condition = conditions[i];

            Encoding encoding = condition.paramType;
            (, uint256 childCount) = Topology.childBounds(conditions, i);
            uint256 inlinedSize = Topology.isInlined(conditions, i)
                ? Topology.inlinedSize(conditions, i)
                : 0;

            bytes memory compValue = condition.compValue;
            uint256 compValueLength = compValue.length;
            bool hasCompValue = compValueLength > 0;

            /*
             * ┌───────────────────────────────────────────────────────────┐
             * │ packed 32 bits, 4 bytes:                                  │
             * │   • encoding              3 bits  [31-29]                 │
             * │   • operator              5 bits  [28-24]                 │
             * │   • childCount           10 bits  [23-14]                 │
             * │   • inlinedSize          13 bits  [13-1]                  │
             * │   • hasCompValue          1 bit   [0]                     │
             * └───────────────────────────────────────────────────────────┘
             */
            uint256 packed = (uint256(encoding) << 29) |
                (uint256(condition.operator) << 24) |
                (childCount << 14) |
                (inlinedSize << 1) |
                (hasCompValue ? 1 : 0);

            /*
             * The or with mload preserves bytes 4-31 (compValues written in
             * previous iterations) while writing our 4 bytes at positions 0-3.
             */
            assembly {
                let dest := add(add(buffer, 0x20), offset)
                mstore(dest, or(mload(dest), shl(224, packed)))
            }
            offset += NODE_BYTES;

            // Pack compValue writes at tail, no preserving required
            if (hasCompValue) {
                assembly {
                    let dest := add(add(buffer, 0x20), compValueOffset)
                    // write 2 bytes length
                    mstore(dest, shl(240, compValueLength))
                    // copy compValue body
                    mcopy(add(dest, 2), add(compValue, 0x20), compValueLength)
                }
                compValueOffset = compValueOffset + 2 + compValueLength;
            }
        }
    }

    function _count(
        ConditionFlat[] memory conditions
    ) private pure returns (uint256 compValuesSize, uint256 maxPluckCount) {
        for (uint256 i; i < conditions.length; ++i) {
            if (conditions[i].operator == Operator.Pluck) {
                uint8 pluckIndex = uint8(conditions[i].compValue[0]);
                if (pluckIndex + 1 > maxPluckCount) {
                    maxPluckCount = pluckIndex + 1;
                }
            }

            uint256 length = conditions[i].compValue.length;
            if (length > 0) {
                compValuesSize += 2 + length;
            }
        }
    }

    /**
     * @dev Normalizes conditions in-place before packing:
     *      1. AbiEncoded without compValue gets default leadingBytes (0x0004)
     *      2. EqualTo at offset has 32-byte head pointer stripped
     */
    function _transform(ConditionFlat[] memory conditions) private pure {
        for (uint256 i; i < conditions.length; ++i) {
            /*
             * Patch AbiEncoded leadingBytes
             *
             * AbiEncoded nodes without compValue need a default leadingBytes of 4
             * (function selector size). Store as 2-byte big-endian value.
             */
            if (
                conditions[i].paramType == Encoding.AbiEncoded &&
                conditions[i].compValue.length == 0
            ) {
                conditions[i].compValue = hex"0004";
            }

            /*
             * Remove Extraneous Offsets
             *
             * Remove unnecessary offsets from compValue fields. This ensures a
             * consistent API where every `compValue` provided for use in
             * `Operator.EqualTo` is obtained by calling `abi.encode` directly.
             *
             * By removing the leading extraneous offset this makes
             * `abi.encode(...)` output line up with the layout produced by
             * Decoder inspection. Without it, callers would need to patch
             * compValues based on whether the payload is fully inline or at
             * offset.
             */
            if (
                conditions[i].operator == Operator.EqualTo &&
                !Topology.isInlined(conditions, i)
            ) {
                bytes memory compValue = conditions[i].compValue;
                assembly {
                    let newLength := sub(mload(compValue), 32)
                    compValue := add(compValue, 32)
                    mstore(compValue, newLength)
                }
                conditions[i].compValue = compValue;
            }
        }
    }
}

